INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7724bc4d-02c9-42c8-9690-31449f7efe5c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hardhat — Leverage Foundry for Efficient Solidity Testing$escape$,
  $escape$Foundry is an open-source framework for building and testing smart contracts in Solidity. To integrate Foundry with Hardhat, you'll need to install the foundry-hHardhat plugin. This plugin enables the use of Forge, a powerful testing framework for Solidity contracts. Forge provides features like fuzz testing and Cast for interactions with contracts. Additionally, you can use Anvil for local node testing. To set up Foundry with Hardhat, run the following command: `npx hardhat foundry init`. Then, create a test file using the Forge test framework. For example, you can use the `@foundry/runkit` plugin to execute your tests in a local environment. To fuzz test a contract, you can use the `@foundry/fuzz` plugin.$escape$,
  $escape$import { ethers } from 'ethers';
import { HardhatRuntimeEnvironment } from 'hardhat/types';

const foundry = require('@foundry-rs/foundry');

function run(hre: HardhatRuntimeEnvironment) {
  const contract = hre.ethers.getContract('MyContract');
  const input = { foo: 'bar' };
  contract.callFunction(input);
}$escape$,
  $escape$typescript$escape$,
